INSERT INTO `v1_dabe8b467201159013e0fcc57503e77537b99b6063d9b61e9fccee19a8b0bf8c` VALUES (1, 0.5, "シズルさまにエリコさま、\nどうかされたのですか？", 0, 19050041, 107611, 905, 11, 0, 10, 0);
INSERT INTO `v1_dabe8b467201159013e0fcc57503e77537b99b6063d9b61e9fccee19a8b0bf8c` VALUES ("", "", "", "", 19050042, 0, 905, 91, "", "", "");
