INSERT INTO `v1_dabe8b467201159013e0fcc57503e77537b99b6063d9b61e9fccee19a8b0bf8c` VALUES (1, 1, "はい、そこの流れてくるおねーさん\nたい焼きいかがかにゃ？", 0, 19440025, 107911, 944, 11, 0, 8, 0);
INSERT INTO `v1_dabe8b467201159013e0fcc57503e77537b99b6063d9b61e9fccee19a8b0bf8c` VALUES ("", "", "", "", 19440026, 0, 944, 91, "", "", "");
