INSERT INTO `v1_dabe8b467201159013e0fcc57503e77537b99b6063d9b61e9fccee19a8b0bf8c` VALUES ("", "", "cmn_boat_idle", "", 19440028, 2, 944, 3, 0.2, 1, "");
INSERT INTO `v1_dabe8b467201159013e0fcc57503e77537b99b6063d9b61e9fccee19a8b0bf8c` VALUES (0, "", "vo_fpc_30403", "", 19440029, "vo_fpc", 944, 21, "", "", "");
INSERT INTO `v1_dabe8b467201159013e0fcc57503e77537b99b6063d9b61e9fccee19a8b0bf8c` VALUES (1, 1, "あら、タマキさんじゃない。\nこんなところで何やってるの？", 0, 19440030, 126811, 944, 11, 0, 10, 0);
INSERT INTO `v1_dabe8b467201159013e0fcc57503e77537b99b6063d9b61e9fccee19a8b0bf8c` VALUES ("", "", "", "", 19440031, 0, 944, 91, "", "", "");
