INSERT INTO `v1_dabe8b467201159013e0fcc57503e77537b99b6063d9b61e9fccee19a8b0bf8c` VALUES (1, 0.5, "大丈夫にゃ。バレないように…\nってやばいにゃ！　見回りだにゃ！", 0, 19440046, 107911, 944, 11, 0, 8, 0);
