INSERT INTO `v1_dabe8b467201159013e0fcc57503e77537b99b6063d9b61e9fccee19a8b0bf8c` VALUES (1, 0.5, "無許可営業は取り締まり対象よ！\n待ちなさい！", 0, 19440062, 108011, 944, 11, 0, 15, 0);
